namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 64;
static constexpr uint32_t HARD_CAP_ELEMS = 8192;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k_01958_CustomTilingData tiling;

    const gert::StorageShape *inShape = context->GetInputShape(0);
    uint32_t totalLength = static_cast<uint32_t>(inShape->GetOriginShape().GetShapeSize());
    uint32_t ndim = static_cast<uint32_t>(inShape->GetOriginShape().GetDimNum());
    uint32_t batchSize = (ndim >= 4) ? static_cast<uint32_t>(inShape->GetOriginShape().GetDim(0)) : 1u;
    uint32_t numChannels = (ndim >= 4) ? static_cast<uint32_t>(inShape->GetOriginShape().GetDim(1)) : 1u;
    uint32_t height = (ndim >= 4) ? static_cast<uint32_t>(inShape->GetOriginShape().GetDim(2)) : 1u;
    uint32_t width = (ndim >= 4) ? static_cast<uint32_t>(inShape->GetOriginShape().GetDim(3)) : 1u;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *eps = attrs->GetAttrPointer<float>(0);
    const bool *affine = attrs->GetAttrPointer<bool>(1);

    // Number of independent channels (each block processes one (n,c) pair)
    uint32_t numBlocks = batchSize * numChannels;
    if (numBlocks == 0) numBlocks = 1;

    uint32_t spatialLen = height * width;
    uint32_t maxTile = UB_BUDGET_BYTES / (3 * sizeof(float));
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);
    uint32_t tileLen = (spatialLen > maxTile) ? maxTile : spatialLen;
    if (tileLen == 0) tileLen = 1;

    context->SetBlockDim(numBlocks);

    tiling.set_totalLength(totalLength);
    tiling.set_batchSize(batchSize);
    tiling.set_numChannels(numChannels);
    tiling.set_height(height);
    tiling.set_width(width);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(numBlocks);
    tiling.set_eps(*eps);
    tiling.set_affine(*affine);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

